// Get sheet rows and existing leads
const sheetRows = $('קריאת גיליון ניהול לידים').all();
const existingLeads = $('שליפת לידים קיימים מ-Supabase').all();

// Build sets of existing identifiers
const existingEmails = new Set(
  existingLeads
    .map(item => (item.json.email || '').toLowerCase().trim())
    .filter(e => e)
);
const existingPhones = new Set(
  existingLeads
    .map(item => (item.json.phone || '').replace(/\D/g, ''))
    .filter(p => p)
);

// Status mapping from Hebrew to enum
const statusMap = {
  'לקוח משלם (סגירה)': 'closed',
  'לקוח משלם': 'closed',
  'סגירה': 'closed',
  'לא רלוונטי': 'lost',
  'לא מתאים': 'lost',
  'מילא שאלון התאמה': 'filled_questionnaire',
  'מילא שאלון': 'filled_questionnaire',
  'שאלון התאמה': 'filled_questionnaire',
  'צפה ב-VSL': 'watched_vsl',
  'צפה בוידאו': 'watched_vsl',
  'שיחת מכירה': 'sales_call',
  'שיחה': 'sales_call',
  'קיבל וואטסאפ': 'got_wa',
  'קיבל הודעה': 'got_wa',
  'חדש': 'new',
  'ליד חדש': 'new'
};

function cleanPhone(raw) {
  if (!raw) return null;
  let phone = raw.toString().replace(/[\s\-\(\)]/g, '');
  // Remove +972 or 972 prefix
  if (phone.startsWith('+972')) phone = '0' + phone.slice(4);
  else if (phone.startsWith('972')) phone = '0' + phone.slice(3);
  // Ensure starts with 0
  if (phone.length === 9 && !phone.startsWith('0')) phone = '0' + phone;
  return phone.length >= 9 && phone.length <= 11 ? phone : null;
}

function parseDate(raw) {
  if (!raw) return null;
  const parts = raw.match(/(\d{1,2})[\/\-\.](\d{1,2})[\/\-\.](\d{2,4})/);
  if (parts) {
    const day = parts[1].padStart(2, '0');
    const month = parts[2].padStart(2, '0');
    const year = parts[3].length === 2 ? '20' + parts[3] : parts[3];
    return `${year}-${month}-${day}T00:00:00.000Z`;
  }
  const parsed = new Date(raw);
  return !isNaN(parsed.getTime()) ? parsed.toISOString() : null;
}

function isFake(name, phone, email) {
  // Single char names
  if (name && name.trim().length <= 1) return true;
  // Obviously fake phones (all same digit)
  if (phone && /^(.)\1+$/.test(phone.replace(/\D/g, ''))) return true;
  // Fake emails
  if (email && (email.includes('test@') || email.includes('fake@') || email.includes('aaa@'))) return true;
  return false;
}

const newLeads = [];
const newNotes = [];

for (const row of sheetRows) {
  const d = row.json;
  const name = (d['שם מלא'] || '').trim();
  const email = (d['מייל'] || '').toLowerCase().trim();
  const rawPhone = d['טלפון'] || '';
  const phone = cleanPhone(rawPhone);

  // Skip if no identifiable info
  if (!email && !phone) continue;

  // Skip fakes
  if (isFake(name, phone, email)) continue;

  // Check if already exists (by email or phone)
  const emailExists = email && existingEmails.has(email);
  const phoneDigits = phone ? phone.replace(/\D/g, '') : '';
  const phoneExists = phoneDigits && existingPhones.has(phoneDigits);
  if (emailExists || phoneExists) continue;

  // Map status
  const sheetStatus = (d['שלב במשפך'] || d['סטטוס ליד'] || '').trim();
  let currentStatus = 'new';
  for (const [key, value] of Object.entries(statusMap)) {
    if (sheetStatus.includes(key) || sheetStatus === key) {
      currentStatus = value;
      break;
    }
  }

  const createdAt = parseDate(d['תאריך יצירה']);

  const lead = {
    name: name || (email ? email.split('@')[0] : 'Unknown'),
    email: email || null,
    phone: phone,
    product: 'simply_grow',
    source: 'campaign',
    current_status: currentStatus
  };
  if (createdAt) lead.created_at = createdAt;
  if (d['מקור']) lead.ad_name = d['מקור'];

  newLeads.push(lead);

  // If there are notes, save them for later
  const notes = (d['הערות'] || '').trim();
  if (notes) {
    newNotes.push({
      lead_email: email,
      lead_phone: phone,
      content: notes,
      lead_name: lead.name
    });
  }
}

return [{ json: { newLeads, newNotes, newLeadsCount: newLeads.length, newNotesCount: newNotes.length } }];
